Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
throughs/async-map.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

function id (e) { return e }
var prop = require('../util/prop')

module.exports = function asyncMap (map) {
  if(!map) return id
  map = prop(map)
  var busy = false, abortCb, aborted
  return function (read) {
    return function next (abort, cb) {
      <PLACEHOLDER>
      if(abort) {
        aborted = abort
        if(!busy) read(abort, function (err) {
          //incase the source has already ended normally,
          //we should pass our own error.
          cb(abort)
        })
        else read(abort, function (err) {
          //if we are still busy, wait for the mapper to complete.
          if(busy) abortCb = cb
          else cb(abort)
        })
      }
      else
        read(null, function (end, data) {
          if(end) cb(end)
          else if(aborted) cb(aborted)
          else {
            busy = true
            map(data, function (err, data) {
              busy = false
              if(aborted) {
                cb(aborted)
                abortCb && abortCb(aborted)
              }
              else if(err) next (err, cb)
              else cb(null, data)
            })
          }
        })
    }
  }
}








In the original code, <PLACEHOLDER> has the value:

-         if(aborted) return cb(aborted)
In the mutated code, <PLACEHOLDER> has the value:

+         if(false) return cb(aborted)


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-3ccb689/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

```typescript
import asyncMap from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/async-map.js";

describe("asyncMap abort after aborted state", () => {
  it("should call cb with abort error when read is called after stream has been aborted", (done) => {
    // Create a source that simulates a slow async operation
    let readCount = 0;
    let pendingCb: ((end: any, data?: any) => void) | null = null;

    const source = (abort: any, cb: (end: any, data?: any) => void) => {
      if (abort) {
        cb(abort);
        return;
      }
      readCount++;
      if (readCount === 1) {
        // First read: hold the callback to simulate async
        pendingCb = cb;
      } else {
        cb(null, readCount);
      }
    };

    const abortError = new Error("abort");
    const results: any[] = [];

    // Create a slow map function that takes time
    let mapCb: ((err: any, data?: any) => void) | null = null;
    const slowMap = (data: any, cb: (err: any, data?: any) => void) => {
      mapCb = cb;
    };

    const through = asyncMap(slowMap)(source);

    // Start reading - this will trigger source read and map
    through(null, (end: any, data: any) => {
      results.push({ end, data });
    });

    // Release the first read so map starts
    if (pendingCb) {
      pendingCb(null, 1);
    }

    // Now abort while map is busy
    through(abortError, (err: any) => {
      results.push({ abortResult: err });
    });

    // Complete the map operation
    if (mapCb) {
      mapCb(null, 100);
    }

    // Now try to read again - with original code, since aborted is set,
    // it should immediately call cb(aborted) without reading from source
    let secondReadCalled = false;
    through(null, (end: any, data: any) => {
      secondReadCalled = true;
      // In original code: cb(aborted) is called immediately
      // In mutated code: it tries to read from source instead
      expect(end).toBe(abortError);
      expect(data).toBeUndefined();
      done();
    });

    // If the mutation is present, the second read won't immediately return aborted
    // and will try to read from source. We need to handle that case.
    // Give it a tick to see if done was called
    setTimeout(() => {
      if (!secondReadCalled) {
        // Mutation detected: cb was not called with aborted error
        done(new Error("Expected cb to be called with abort error immediately, but it was not called"));
      }
    }, 50);
  });
});
```

Looking at the mutation more carefully:

- Original: `if(aborted) return cb(aborted)` - at the start of the `next` function, if already aborted, immediately call cb with the abort error
- Mutated: `if(false) return cb(aborted)` - this check is disabled, so even if already aborted, it proceeds normally

The key behavior to test: after a stream has been aborted, subsequent calls to `next` should immediately invoke `cb` with the abort error (original), but with the mutation they won't.

```typescript
import asyncMap from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/async-map.js";

describe("asyncMap", () => {
  it("should immediately call cb with abort error on subsequent reads after stream is aborted", (done) => {
    const abortError = new Error("abort");
    let sourceCallCount = 0;

    // Source that tracks how many times it's called
    const source = (abort: any, cb: (end: any, data?: any) => void) => {
      sourceCallCount++;
      if (abort) {
        cb(abort);
        return;
      }
      // Provide data normally
      cb(null, sourceCallCount);
    };

    const identity = (data: any, cb: (err: any, data?: any) => void) => {
      cb(null, data);
    };

    const through = asyncMap(identity)(source);

    // First, abort the stream
    through(abortError, (err: any) => {
      // Stream is now aborted
      expect(err).toBe(abortError);

      const sourceCallsAfterAbort = sourceCallCount;

      // Now try to read again after abort - original code should immediately
      // return cb(aborted) WITHOUT calling source again
      through(null, (end: any, data: any) => {
        // In original: cb is called with abortError immediately (no new source call)
        // In mutated: the aborted check is skipped, source gets called again
        expect(end).toBe(abortError);

        // In original code, source should NOT have been called again
        // because the early return `if(aborted) return cb(aborted)` fires first
        expect(sourceCallCount).toBe(sourceCallsAfterAbort);

        done();
      });
    });
  });
});
```
